export type FlagStatus =
  | "none"
  | "needs_review"
  | "approved"
  | "disputed"
  | "archived";

export type SourceType =
  | "online"
  | "user_defined"
  | "pdf_import"
  | "llm_generated";

export interface Source {
  id: number;
  name: string;
  type: SourceType;
  url: string | null;
  is_active: boolean;
}

export interface Definition {
  id: number;
  term_id: number;
  source_id: number | null;
  text: string;
  part_of_speech: string | null;
  example: string | null;
  is_llm_generated: boolean;
  is_primary: boolean;
  source: Source | null;
  created_at: string;
}

export interface Term {
  id: number;
  word: string;
  normalized_word: string;
  flag_status: FlagStatus;
  is_custom: boolean;
  category: string | null;
  notes: string | null;
  definitions: Definition[];
  created_at: string;
  updated_at: string;
}

export interface TermSummary {
  id: number;
  word: string;
  flag_status: FlagStatus;
  is_custom: boolean;
  category: string | null;
  definition_count: number;
  created_at: string;
  updated_at: string;
}

export interface DashboardStats {
  total_terms: number;
  approved_terms: number;
  needs_review_terms: number;
  custom_terms: number;
  total_definitions: number;
  total_sources: number;
  recent_terms: TermSummary[];
}

export interface LookupResult {
  word: string;
  definitions: Definition[];
  sources_searched: string[];
  new_definitions_added: number;
}

