import type {
  DashboardStats,
  Definition,
  FlagStatus,
  LookupResult,
  Source,
  Term,
  TermSummary,
} from "./types";

const API_BASE = "/api";

async function fetchAPI<T>(
  path: string,
  options?: RequestInit
): Promise<T> {
  const res = await fetch(`${API_BASE}${path}`, {
    headers: { "Content-Type": "application/json", ...options?.headers },
    ...options,
  });
  if (!res.ok) {
    const error = await res.text();
    throw new Error(error || `API error: ${res.status}`);
  }
  if (res.status === 204) return undefined as T;
  return res.json();
}

// Terms
export async function getTerms(params?: {
  q?: string;
  flag_status?: FlagStatus;
  category?: string;
  is_custom?: boolean;
  skip?: number;
  limit?: number;
}): Promise<TermSummary[]> {
  const searchParams = new URLSearchParams();
  if (params?.q) searchParams.set("q", params.q);
  if (params?.flag_status) searchParams.set("flag_status", params.flag_status);
  if (params?.category) searchParams.set("category", params.category);
  if (params?.is_custom !== undefined)
    searchParams.set("is_custom", String(params.is_custom));
  if (params?.skip) searchParams.set("skip", String(params.skip));
  if (params?.limit) searchParams.set("limit", String(params.limit));
  const qs = searchParams.toString();
  return fetchAPI<TermSummary[]>(`/terms${qs ? `?${qs}` : ""}`);
}

export async function getTerm(id: number): Promise<Term> {
  return fetchAPI<Term>(`/terms/${id}`);
}

export async function createTerm(data: {
  word: string;
  category?: string;
  notes?: string;
  definition?: string;
}): Promise<Term> {
  return fetchAPI<Term>("/terms", {
    method: "POST",
    body: JSON.stringify(data),
  });
}

export async function updateTerm(
  id: number,
  data: {
    word?: string;
    category?: string;
    notes?: string;
    flag_status?: FlagStatus;
  }
): Promise<Term> {
  return fetchAPI<Term>(`/terms/${id}`, {
    method: "PUT",
    body: JSON.stringify(data),
  });
}

export async function deleteTerm(id: number): Promise<void> {
  return fetchAPI<void>(`/terms/${id}`, { method: "DELETE" });
}

export async function flagTerm(
  id: number,
  data: { flag_status: FlagStatus; notes?: string }
): Promise<Term> {
  return fetchAPI<Term>(`/terms/${id}/flag`, {
    method: "PUT",
    body: JSON.stringify(data),
  });
}

// Definitions
export async function addDefinition(
  termId: number,
  data: {
    text: string;
    part_of_speech?: string;
    example?: string;
    source_id?: number;
    is_primary?: boolean;
  }
): Promise<Definition> {
  return fetchAPI<Definition>(`/terms/${termId}/definitions`, {
    method: "POST",
    body: JSON.stringify(data),
  });
}

// Lookup
export async function lookupWord(word: string): Promise<LookupResult> {
  return fetchAPI<LookupResult>(`/lookup/${encodeURIComponent(word)}`, {
    method: "POST",
  });
}

// Dashboard
export async function getStats(): Promise<DashboardStats> {
  return fetchAPI<DashboardStats>("/terms/stats");
}

// Sources
export async function getSources(): Promise<Source[]> {
  return fetchAPI<Source[]>("/sources");
}

