"use client";

import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Select } from "@/components/ui/select";
import { createTerm } from "@/lib/api";
import { useState } from "react";

const CATEGORIES = [
  "Governance",
  "Risk Management",
  "Regulatory",
  "Assurance",
  "Information",
  "General",
];

interface AddTermDialogProps {
  open: boolean;
  onClose: () => void;
  onSuccess: () => void;
}

export function AddTermDialog({ open, onClose, onSuccess }: AddTermDialogProps) {
  const [word, setWord] = useState("");
  const [category, setCategory] = useState("");
  const [definition, setDefinition] = useState("");
  const [notes, setNotes] = useState("");
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!word.trim()) return;

    setLoading(true);
    try {
      await createTerm({
        word: word.trim(),
        category: category || undefined,
        notes: notes || undefined,
        definition: definition || undefined,
      });
      setWord("");
      setCategory("");
      setDefinition("");
      setNotes("");
      onSuccess();
      onClose();
    } catch (err) {
      console.error("Failed to create term:", err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <Dialog open={open} onClose={onClose}>
      <form onSubmit={handleSubmit}>
        <DialogHeader>
          <DialogTitle>Add New Term</DialogTitle>
        </DialogHeader>
        <DialogContent>
          <div className="space-y-4">
            <div>
              <label className="text-sm font-medium text-foreground">
                Term <span className="text-destructive">*</span>
              </label>
              <Input
                value={word}
                onChange={(e) => setWord(e.target.value)}
                placeholder="e.g. Framework"
                className="mt-1.5"
                autoFocus
              />
            </div>
            <div>
              <label className="text-sm font-medium text-foreground">
                Category
              </label>
              <Select
                value={category}
                onChange={(e) => setCategory(e.target.value)}
                className="mt-1.5"
              >
                <option value="">Select a category...</option>
                {CATEGORIES.map((cat) => (
                  <option key={cat} value={cat}>
                    {cat}
                  </option>
                ))}
              </Select>
            </div>
            <div>
              <label className="text-sm font-medium text-foreground">
                Definition
              </label>
              <textarea
                value={definition}
                onChange={(e) => setDefinition(e.target.value)}
                placeholder="Enter a business definition for this term..."
                rows={3}
                className="mt-1.5 flex w-full rounded-md border border-input bg-transparent px-3 py-2 text-sm shadow-sm placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring resize-none"
              />
            </div>
            <div>
              <label className="text-sm font-medium text-foreground">
                Notes
              </label>
              <Input
                value={notes}
                onChange={(e) => setNotes(e.target.value)}
                placeholder="Optional notes..."
                className="mt-1.5"
              />
            </div>
          </div>
        </DialogContent>
        <DialogFooter>
          <Button type="button" variant="outline" onClick={onClose}>
            Cancel
          </Button>
          <Button type="submit" disabled={!word.trim() || loading}>
            {loading ? "Adding..." : "Add Term"}
          </Button>
        </DialogFooter>
      </form>
    </Dialog>
  );
}

