"use client";

import { FlagBadge } from "@/components/flag-badge";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Skeleton } from "@/components/ui/skeleton";
import { getStats } from "@/lib/api";
import type { DashboardStats } from "@/lib/types";
import { useQuery } from "@tanstack/react-query";
import {
  BookCheck,
  BookOpen,
  CircleAlert,
  Database,
  Library,
  UserPen,
} from "lucide-react";
import Link from "next/link";

function StatCard({
  title,
  value,
  icon: Icon,
  description,
}: {
  title: string;
  value: number;
  icon: React.ElementType;
  description?: string;
}) {
  return (
    <Card className="hover:shadow-md transition-shadow">
      <CardHeader className="flex flex-row items-center justify-between pb-2">
        <CardTitle className="text-sm font-medium text-muted-foreground">
          {title}
        </CardTitle>
        <Icon className="h-4 w-4 text-muted-foreground" />
      </CardHeader>
      <CardContent>
        <div className="text-3xl font-bold">{value}</div>
        {description && (
          <p className="text-xs text-muted-foreground mt-1">{description}</p>
        )}
      </CardContent>
    </Card>
  );
}

function StatsSkeleton() {
  return (
    <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
      {Array.from({ length: 6 }).map((_, i) => (
        <Card key={i}>
          <CardHeader className="pb-2">
            <Skeleton className="h-4 w-24" />
          </CardHeader>
          <CardContent>
            <Skeleton className="h-8 w-16" />
            <Skeleton className="mt-1 h-3 w-32" />
          </CardContent>
        </Card>
      ))}
    </div>
  );
}

export default function DashboardPage() {
  const { data: stats, isLoading } = useQuery<DashboardStats>({
    queryKey: ["stats"],
    queryFn: getStats,
  });

  return (
    <div className="space-y-8">
      {/* Page header */}
      <div>
        <h1 className="text-2xl font-bold tracking-tight">Dashboard</h1>
        <p className="text-muted-foreground">
          Overview of your data dictionary
        </p>
      </div>

      {/* Stats grid */}
      {isLoading || !stats ? (
        <StatsSkeleton />
      ) : (
        <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
          <StatCard
            title="Total Terms"
            value={stats.total_terms}
            icon={BookOpen}
            description="Terms in dictionary"
          />
          <StatCard
            title="Approved"
            value={stats.approved_terms}
            icon={BookCheck}
            description="Reviewed & approved"
          />
          <StatCard
            title="Needs Review"
            value={stats.needs_review_terms}
            icon={CircleAlert}
            description="Awaiting review"
          />
          <StatCard
            title="Custom Terms"
            value={stats.custom_terms}
            icon={UserPen}
            description="Business-defined"
          />
          <StatCard
            title="Definitions"
            value={stats.total_definitions}
            icon={Database}
            description="Across all sources"
          />
          <StatCard
            title="Sources"
            value={stats.total_sources}
            icon={Library}
            description="Dictionary sources"
          />
        </div>
      )}

      {/* Recent terms */}
      <div>
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-lg font-semibold">Recent Terms</h2>
          <Link
            href="/terms"
            className="text-sm text-primary hover:underline"
          >
            View all
          </Link>
        </div>
        {isLoading || !stats ? (
          <div className="space-y-2">
            {Array.from({ length: 5 }).map((_, i) => (
              <Skeleton key={i} className="h-14 w-full" />
            ))}
          </div>
        ) : (
          <Card>
            <div className="divide-y">
              {stats.recent_terms.map((term) => (
                <Link
                  key={term.id}
                  href={`/terms/${term.id}`}
                  className="flex items-center justify-between p-4 hover:bg-muted/50 transition-colors"
                >
                  <div className="flex items-center gap-3">
                    <span className="font-mono font-medium">{term.word}</span>
                    <FlagBadge status={term.flag_status} />
                    {term.category && (
                      <span className="text-xs text-muted-foreground">
                        {term.category}
                      </span>
                    )}
                  </div>
                  <span className="text-sm text-muted-foreground">
                    {term.definition_count} definition
                    {term.definition_count !== 1 ? "s" : ""}
                  </span>
                </Link>
              ))}
              {stats.recent_terms.length === 0 && (
                <div className="p-8 text-center text-muted-foreground">
                  No terms yet. Add your first term to get started.
                </div>
              )}
            </div>
          </Card>
        )}
      </div>
    </div>
  );
}

