import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Select } from "@/components/ui/select";
import { Skeleton } from "@/components/ui/skeleton";
import { getTerms } from "@/lib/api";
import type { FlagStatus, TermSummary } from "@/lib/types";
import { useQuery } from "@tanstack/react-query";
import { Plus, Search } from "lucide-react";
import Link from "next/link";
import { useState } from "react";

export default function TermsPage() {
  const [search, setSearch] = useState("");
  const [flagFilter, setFlagFilter] = useState<FlagStatus | "">("");
  const [showAddDialog, setShowAddDialog] = useState(false);

  const { data: terms, isLoading, refetch } = useQuery<TermSummary[]>({
    queryKey: ["terms", search, flagFilter],
    queryFn: () =>
      getTerms({
        q: search || undefined,
        flag_status: (flagFilter as FlagStatus) || undefined,
        limit: 100,
      }),
  });

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">Terms</h1>
          <p className="text-muted-foreground">
            Browse and manage your data dictionary terms
          </p>
        </div>
        <Button onClick={() => setShowAddDialog(true)}>
          <Plus className="h-4 w-4" />
          Add Term
        </Button>
      </div>

      {/* Filters */}
      <div className="flex flex-wrap items-center gap-3">
        <div className="relative flex-1 min-w-[200px] max-w-md">
          <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
          <Input
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder="Search terms..."
            className="pl-9"
          />
        </div>
        <Select
          value={flagFilter}
          onChange={(e) => setFlagFilter(e.target.value as FlagStatus | "")}
          className="w-40"
        >
          <option value="">All statuses</option>
          <option value="none">Unset</option>
          <option value="needs_review">Needs Review</option>
          <option value="approved">Approved</option>
          <option value="disputed">Disputed</option>
          <option value="archived">Archived</option>
        </Select>
        {terms && (
          <span className="text-sm text-muted-foreground">
            {terms.length} term{terms.length !== 1 ? "s" : ""}
          </span>
        )}
      </div>

      {/* Terms table */}
      {isLoading ? (
        <div className="space-y-2">
          {Array.from({ length: 10 }).map((_, i) => (
            <Skeleton key={i} className="h-14 w-full" />
          ))}
        </div>
      ) : (
        <Card>
          {/* Table header */}
          <div className="grid grid-cols-[1fr_120px_120px_100px] gap-4 border-b px-4 py-3 text-xs font-medium text-muted-foreground uppercase tracking-wider">
            <span>Term</span>
            <span>Category</span>
            <span>Status</span>
            <span className="text-right">Definitions</span>
          </div>
          {/* Rows */}
          <div className="divide-y">
            {terms?.map((term) => (
              <Link
                key={term.id}
                href={`/terms/${term.id}`}
                className="grid grid-cols-[1fr_120px_120px_100px] gap-4 items-center px-4 py-3 hover:bg-muted/50 transition-colors"
              >
                <div className="flex items-center gap-2">
                  <span className="font-mono font-medium">{term.word}</span>
                  {term.is_custom && (
                    <Badge variant="purple" className="text-[10px]">
                      Custom
                    </Badge>
                  )}
                </div>
                <span className="text-sm text-muted-foreground">
                  {term.category || "-"}
                </span>
                <FlagBadge status={term.flag_status} />
                <span className="text-sm text-muted-foreground text-right">
                  {term.definition_count}
                </span>
              </Link>
            ))}
            {terms?.length === 0 && (
              <div className="p-12 text-center text-muted-foreground">
                <p className="text-lg font-medium">No terms found</p>
                <p className="text-sm mt-1">
                  Try adjusting your search or filters, or add a new term.
                </p>
              </div>
            )}
          </div>
        </Card>
      )}

      <AddTermDialog
        open={showAddDialog}
        onClose={() => setShowAddDialog(false)}
        onSuccess={() => refetch()}
      />
    </div>
  );
}

