      <p className="text-sm leading-relaxed">{definition.text}</p>
      {definition.example && (
        <p className="text-xs text-muted-foreground italic border-l-2 border-primary/20 pl-3">
          &ldquo;{definition.example}&rdquo;
        </p>
      )}
    </div>
  );
}

function groupBySource(definitions: Definition[]) {
  const groups: Record<string, Definition[]> = {};
  for (const def of definitions) {
    const source = def.source?.name || "Unknown";
    if (!groups[source]) groups[source] = [];
    groups[source].push(def);
  }
  return groups;
}

export default function TermDetailPage() {
  const params = useParams();
  const id = Number(params.id);
  const queryClient = useQueryClient();
  const [lookingUp, setLookingUp] = useState(false);
  const [lookupResult, setLookupResult] = useState<string | null>(null);

  const { data: term, isLoading } = useQuery<Term>({
    queryKey: ["term", id],
    queryFn: () => getTerm(id),
    enabled: !!id,
  });

  const handleLookup = async () => {
    if (!term) return;
    setLookingUp(true);
    setLookupResult(null);
    try {
      const result = await lookupWord(term.word);
      setLookupResult(
        `Found ${result.new_definitions_added} new definition${result.new_definitions_added !== 1 ? "s" : ""} from ${result.sources_searched.join(", ")}`
      );
      queryClient.invalidateQueries({ queryKey: ["term", id] });
      queryClient.invalidateQueries({ queryKey: ["stats"] });
    } catch (err) {
      setLookupResult("Lookup failed. Please try again.");
      console.error(err);
    } finally {
      setLookingUp(false);
    }
  };

  const handleFlagChange = async (newStatus: string) => {
    if (!term) return;
    await flagTerm(term.id, { flag_status: newStatus as FlagStatus });
    queryClient.invalidateQueries({ queryKey: ["term", id] });
    queryClient.invalidateQueries({ queryKey: ["stats"] });
  };

  if (isLoading) {
    return (
      <div className="space-y-6">
        <Skeleton className="h-8 w-48" />
        <Skeleton className="h-32 w-full" />
        <Skeleton className="h-64 w-full" />
      </div>
    );
  }

  if (!term) {
    return (
      <div className="text-center py-12">
        <p className="text-lg text-muted-foreground">Term not found</p>
        <Link href="/terms" className="text-primary hover:underline mt-2 block">
          Back to terms
        </Link>
      </div>
    );
  }

  const grouped = groupBySource(term.definitions);

  return (
    <div className="space-y-6">
      {/* Breadcrumb */}
      <Link
        href="/terms"
        className="inline-flex items-center gap-1 text-sm text-muted-foreground hover:text-foreground transition-colors"
      >
        <ArrowLeft className="h-4 w-4" />
        Back to Terms
      </Link>

      {/* Term header */}
      <div className="flex flex-col sm:flex-row sm:items-start sm:justify-between gap-4">
        <div>
          <div className="flex items-center gap-3">
            <h1 className="text-3xl font-bold font-mono">{term.word}</h1>
            <FlagBadge status={term.flag_status} />
            {term.is_custom && <Badge variant="purple">Custom</Badge>}
          </div>
          <div className="flex items-center gap-3 mt-2 text-sm text-muted-foreground">
            {term.category && (
              <span className="flex items-center gap-1">
                <BookOpen className="h-3.5 w-3.5" />
                {term.category}
              </span>
            )}
            <span>
              {term.definitions.length} definition
              {term.definitions.length !== 1 ? "s" : ""}
            </span>
          </div>
          {term.notes && (
            <p className="text-sm text-muted-foreground mt-2 italic">
              {term.notes}
            </p>
          )}
        </div>

        <div className="flex items-center gap-2">
          <Select
            value={term.flag_status}
            onChange={(e) => handleFlagChange(e.target.value)}
            className="w-36"
          >
            <option value="none">Unset</option>
            <option value="needs_review">Needs Review</option>
            <option value="approved">Approved</option>
            <option value="disputed">Disputed</option>
            <option value="archived">Archived</option>
          </Select>
          <Button onClick={handleLookup} disabled={lookingUp}>
            {lookingUp ? (
              <Loader2 className="h-4 w-4 animate-spin" />
            ) : (
              <Globe className="h-4 w-4" />
            )}
            {lookingUp ? "Looking up..." : "Lookup"}
          </Button>
        </div>
      </div>

      {/* Lookup result toast */}
      {lookupResult && (
        <div className="rounded-lg border bg-primary/5 border-primary/20 p-3 flex items-center gap-2">
          <Search className="h-4 w-4 text-primary" />
          <span className="text-sm">{lookupResult}</span>
          <button
            onClick={() => setLookupResult(null)}
            className="ml-auto text-xs text-muted-foreground hover:text-foreground"
          >
            Dismiss
          </button>
        </div>
      )}

      {/* Definitions grouped by source */}
      {Object.keys(grouped).length === 0 ? (
        <Card>
          <CardContent className="py-12 text-center">
            <Globe className="h-8 w-8 text-muted-foreground mx-auto mb-3" />
            <p className="text-muted-foreground">
              No definitions yet. Click{" "}
              <span className="font-medium text-foreground">Lookup</span> to
              search external dictionaries.
            </p>
          </CardContent>
        </Card>
      ) : (
        Object.entries(grouped).map(([source, defs]) => (
          <Card key={source}>
            <CardHeader className="pb-3">
              <div className="flex items-center justify-between">
                <CardTitle className="text-base flex items-center gap-2">
                  <SourceBadge name={source} />
                  <span className="text-muted-foreground font-normal text-sm">
                    {defs.length} definition{defs.length !== 1 ? "s" : ""}
                  </span>
                </CardTitle>
              </div>
            </CardHeader>
            <CardContent className="space-y-3">
              {defs.map((def) => (
                <DefinitionCard key={def.id} definition={def} />
              ))}
            </CardContent>
          </Card>
        ))
      )}
    </div>
  );
}

