"use client";

import { FlagBadge } from "@/components/flag-badge";
import { SourceBadge } from "@/components/source-badge";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { getTerms, lookupWord } from "@/lib/api";
import type { LookupResult, TermSummary } from "@/lib/types";
import { useQuery } from "@tanstack/react-query";
import { Globe, Loader2, Search as SearchIcon } from "lucide-react";
import Link from "next/link";
import { useState } from "react";

export default function SearchPage() {
  const [query, setQuery] = useState("");
  const [lookingUp, setLookingUp] = useState(false);
  const [lookupResult, setLookupResult] = useState<LookupResult | null>(null);

  const { data: matchingTerms } = useQuery<TermSummary[]>({
    queryKey: ["search-terms", query],
    queryFn: () => getTerms({ q: query, limit: 20 }),
    enabled: query.length >= 2,
  });

  const handleLookup = async () => {
    if (!query.trim()) return;
    setLookingUp(true);
    try {
      const result = await lookupWord(query.trim());
      setLookupResult(result);
    } catch (err) {
      console.error("Lookup failed:", err);
    } finally {
      setLookingUp(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "Enter") {
      handleLookup();
    }
  };

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold tracking-tight">Search</h1>
        <p className="text-muted-foreground">
          Search your dictionary or look up terms from external sources
        </p>
      </div>

      {/* Search box */}
      <div className="flex gap-2">
        <div className="relative flex-1">
          <SearchIcon className="absolute left-3 top-1/2 h-5 w-5 -translate-y-1/2 text-muted-foreground" />
          <Input
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="Type a word to search or look up..."
            className="pl-10 h-12 text-lg"
            autoFocus
          />
        </div>
        <Button
          onClick={handleLookup}
          disabled={!query.trim() || lookingUp}
          className="h-12 px-6"
        >
          {lookingUp ? (
            <Loader2 className="h-4 w-4 animate-spin" />
          ) : (
            <Globe className="h-4 w-4" />
          )}
          Look up
        </Button>
      </div>

      {/* Matching existing terms */}
      {query.length >= 2 && matchingTerms && matchingTerms.length > 0 && (
        <Card>
          <CardHeader className="pb-3">
            <CardTitle className="text-sm font-medium text-muted-foreground">
              Existing terms matching &ldquo;{query}&rdquo;
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="divide-y -mt-2">
              {matchingTerms.map((term) => (
                <Link
                  key={term.id}
                  href={`/terms/${term.id}`}
                  className="flex items-center justify-between py-3 hover:bg-muted/50 -mx-2 px-2 rounded-md transition-colors"
                >
                  <div className="flex items-center gap-2">
                    <span className="font-mono font-medium">{term.word}</span>
                    <FlagBadge status={term.flag_status} />
                    {term.category && (
                      <span className="text-xs text-muted-foreground">
                        {term.category}
                      </span>
                    )}
                  </div>
                  <span className="text-sm text-muted-foreground">
                    {term.definition_count} def
                    {term.definition_count !== 1 ? "s" : ""}
                  </span>
                </Link>
              ))}
            </div>
          </CardContent>
        </Card>
      )}

      {/* Lookup results */}
      {lookupResult && (
        <Card>
          <CardHeader>
            <div className="flex items-center justify-between">
              <CardTitle className="flex items-center gap-2">
                <Globe className="h-5 w-5 text-primary" />
                Lookup: &ldquo;{lookupResult.word}&rdquo;
              </CardTitle>
              <Badge variant="info">
                {lookupResult.new_definitions_added} new
              </Badge>
            </div>
            <p className="text-sm text-muted-foreground">
              Searched: {lookupResult.sources_searched.join(", ")}
            </p>
          </CardHeader>
          <CardContent>
            {lookupResult.definitions.length === 0 ? (
              <p className="text-muted-foreground text-center py-6">
                No definitions found for &ldquo;{lookupResult.word}&rdquo;
              </p>
            ) : (
              <div className="space-y-3">
                {lookupResult.definitions.map((def) => (
                  <div
                    key={def.id}
                    className="rounded-lg border p-4 space-y-2"
                  >
                    <div className="flex items-center gap-2">
                      {def.source && <SourceBadge name={def.source.name} />}
                      {def.part_of_speech && (
                        <span className="text-xs italic text-muted-foreground">
                          {def.part_of_speech}
                        </span>
                      )}
                    </div>
                    <p className="text-sm leading-relaxed">{def.text}</p>
                    {def.example && (
                      <p className="text-xs text-muted-foreground italic border-l-2 border-primary/20 pl-3">
                        &ldquo;{def.example}&rdquo;
                      </p>
                    )}
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>
      )}

      {/* Empty state */}
      {!query && !lookupResult && (
        <div className="text-center py-16">
          <SearchIcon className="h-12 w-12 text-muted-foreground/30 mx-auto mb-4" />
          <h2 className="text-lg font-medium text-muted-foreground">
            Search your data dictionary
          </h2>
          <p className="text-sm text-muted-foreground mt-1">
            Type a term to search existing definitions or look up new ones from
            external dictionaries.
          </p>
        </div>
      )}
    </div>
  );
}

