                        {term.category}
                      </span>
                    )}
                  </div>
                  <span className="text-sm text-muted-foreground">
                    {term.definition_count} def
                    {term.definition_count !== 1 ? "s" : ""}
                  </span>
                </Link>
              ))}
            </div>
          </CardContent>
        </Card>
      )}

      {/* Lookup results */}
      {lookupResult && (
        <Card>
          <CardHeader>
            <div className="flex items-center justify-between">
              <CardTitle className="flex items-center gap-2">
                <Globe className="h-5 w-5 text-primary" />
                Lookup: &ldquo;{lookupResult.word}&rdquo;
              </CardTitle>
              <Badge variant="info">
                {lookupResult.new_definitions_added} new
              </Badge>
            </div>
            <p className="text-sm text-muted-foreground">
              Searched: {lookupResult.sources_searched.join(", ")}
            </p>
          </CardHeader>
          <CardContent>
            {lookupResult.definitions.length === 0 ? (
              <p className="text-muted-foreground text-center py-6">
                No definitions found for &ldquo;{lookupResult.word}&rdquo;
              </p>
            ) : (
              <div className="space-y-3">
                {lookupResult.definitions.map((def) => (
                  <div
                    key={def.id}
                    className="rounded-lg border p-4 space-y-2"
                  >
                    <div className="flex items-center gap-2">
                      {def.source && <SourceBadge name={def.source.name} />}
                      {def.part_of_speech && (
                        <span className="text-xs italic text-muted-foreground">
                          {def.part_of_speech}
                        </span>
                      )}
                    </div>
                    <p className="text-sm leading-relaxed">{def.text}</p>
                    {def.example && (
                      <p className="text-xs text-muted-foreground italic border-l-2 border-primary/20 pl-3">
                        &ldquo;{def.example}&rdquo;
                      </p>
                    )}
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>
      )}

      {/* Empty state */}
      {!query && !lookupResult && (
        <div className="text-center py-16">
          <SearchIcon className="h-12 w-12 text-muted-foreground/30 mx-auto mb-4" />
          <h2 className="text-lg font-medium text-muted-foreground">
            Search your data dictionary
          </h2>
          <p className="text-sm text-muted-foreground mt-1">
            Type a term to search existing definitions or look up new ones from
            external dictionaries.
          </p>
        </div>
      )}
    </div>
  );
}

